  if (Pred2 == ICmpInst::ICMP_ULT && match(RHS0, m_Add(m_Value(), m_Value()))) {
    Add2 = RHS0;
    Other2 = RHS1;
  } else if (Pred2 == ICmpInst::ICMP_UGT && match(LHS1, m_Add(m_Value(), m_Value()))) {
    Add2 = LHS1;
    Other2 = RHS0;
  } else {
    return nullptr;
